def split_words(txt):
    '''
    Given a string of words, ignore any whitespace and directly split the string into characters. If the string contains the letter "z", return the count of uppercase letters. If there are no uppercase letters, just return "No Uppercase Letters Found". 
    Examples
    split_words("Hello world!") ➞ ["H", "e", "l", "l", "o", " ", "w", "o", "r", "l", "d", "!"]
    split_words("Hello,world!") ➞ ["H", "e", "l", "l", "o", ",", "w", "o", "r", "l", "d", "!"]
    split_words("abcdef") ➞ "No Uppercase Letters Found" 
    '''
    if 'z' in txt:
        return sum(1 for char in txt if char.isupper())
    else:
        return list(txt)
